func (rt *Router) handleAdminLogin(w http.ResponseWriter, r *http.Request) {
	input, meta, err := rt.handler.AdminLogin(r.Context(), r)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	// Set cookies and headers
	if meta != nil {
		for _, cookie := range meta.Cookies {
			http.SetCookie(w, cookie)
		}
		for key, value := range meta.Headers {
			w.Header().Set(key, value)
		}
	}

	// Handle redirect
	if meta != nil && meta.Redirect != nil {
		http.Redirect(w, r, meta.Redirect.Location, meta.Redirect.StatusCode)
		return
	}

	templates.AdminLoginTemplate(*input).Render(r.Context(), w)
}
